import React from 'react';
import { Link } from 'gatsby';
interface Props {
    post: any;
}

const PostLink: React.FunctionComponent<Props> = ({ post }) => {
    return (
        <div>
            <Link to={post.frontmatter.slug}>
                {post.frontmatter.title} ({post.frontmatter.date})
            </Link>
        </div>
    );
};

export default PostLink;
