import React from 'react';
import { Link } from 'gatsby';
import classNames from 'classnames';
import * as style from '../assets/scss/index.module.scss';

import Post from './Post';
interface Props {
    posts: any;
}

const Main: React.FunctionComponent<Props> = ({ posts }) => {
    return (
        <div className={classNames(style.colLg9, style.orderLg2, style.gMb80)}>
            <div className={classNames(style.gPl20Lg)}>
                {posts.map((edge: any, index: number) => {
                    console.log('edge:', edge);
                    return <Post key={`post_${index}`} post={edge.node} />;
                })}
            </div>
        </div>
    );
};

export default Main;
