import React from 'react';
import { graphql } from 'gatsby';
import Layout from '../components/Layout';
import Main from '../components/Main';
import PostLink from '../components/PostLink';
interface Props {
    data: any;
}

const Index: React.FunctionComponent<Props> = ({ data }) => {
    const {
        allMdx: { edges },
    }: any = data;
    console.log('edges:', edges);
    const Posts = edges
        .filter((edge: any) => !!edge.node.frontmatter.date) // You can filter your posts based on some criteria
        .map((edge: any) => <PostLink key={edge.node.id} post={edge.node} />);
    const posts = edges.filter((edge: any) => !!edge.node.frontmatter.date);
    return (
        <Layout>
            <Main posts={posts} />
        </Layout>
    );
};

export const pageQuery = graphql`
    query {
        allMdx(sort: { order: DESC, fields: [frontmatter___date] }) {
            edges {
                node {
                    id
                    excerpt(pruneLength: 250)
                    frontmatter {
                        date(formatString: "MMMM DD, YYYY")
                        tags
                        description
                        title
                        slug
                    }
                }
            }
        }
    }
`;

export default Index;
